      if (match(Op, m_SMax(m_SMin(m_Value(X), m_APInt(Hi)), m_APInt(Lo))) ||
          match(Op, m_SMax(m_SMin(m_APInt(Hi), m_Value(X)), m_APInt(Lo))) ||
          match(Op, m_SMax(m_APInt(Lo), m_SMin(m_Value(X), m_APInt(Hi)))) ||
