          match(Op, m_UMin(m_UMax(m_APInt(Lo), m_Value(X)), m_APInt(Hi))) ||
          match(Op, m_UMin(m_APInt(Hi), m_UMax(m_Value(X), m_APInt(Lo)))) ||
          match(Op, m_UMin(m_APInt(Hi), m_UMax(m_APInt(Lo), m_Value(X))))) {
        IsSigned = false;
        return true;
      }
      // umax(umin(X, Hi), Lo)
      if (match(Op, m_UMax(m_UMin(m_Value(X), m_APInt(Hi)), m_APInt(Lo))) ||
          match(Op, m_UMax(m_UMin(m_APInt(Hi), m_Value(X)), m_APInt(Lo))) ||
          match(Op, m_UMax(m_APInt(Lo), m_UMin(m_Value(X), m_APInt(Hi)))) ||
          match(Op, m_UMax(m_APInt(Lo), m_UMin(m_APInt(Hi), m_Value(X))))) {
