    // Returns true if decomposition succeeded (A and B are non-null, C is constant).
    auto DecomposeAdd = [&](Value *X, Value *&A, Value *&B, APInt &C) -> bool {
      C = APInt(X->getType()->getScalarSizeInBits(), 0);
