        APInt NewC = C + ConstOffset;
        // Build (A + NewC) + B, with constant on the right side.
        Value *Sum = Builder.CreateAdd(A, ConstantInt::get(X->getType(), NewC));
        Sum = Builder.CreateAdd(Sum, B);
