      return new ICmpInst(NewPred, XSubLo,
                          ConstantInt::get(X->getType(), Diff));
    };
    // Try Op0 then Op1.
    for (Value *Op : {Op0, Op1}) {
      if (MatchClamp(Op)) {
        // Check that Lo <= Hi according to signedness.
        if ((IsSigned && Lo->sle(*Hi)) || (!IsSigned && Lo->ule(*Hi))) {
          return BuildRangeCheck(*Lo, *Hi);
